code_examples.code:
import "../shared/index.tsp";

namespace MyDomain;

@friendlyName("MyResource")
model MyResource {
  ...Shared.ResourceWithKey;

  @visibility(Lifecycle.Read, Lifecycle.Create, Lifecycle.Update)
  @summary("Status")
  status: MyStatus;
}

interface MyResourceOperations {
  @post @operationId("create-my-resource")
  create(@body res: Shared.CreateRequest<MyResource>): Shared.CreateResponse<MyResource> | Common.ErrorResponses;

  @get @route("/{id}") @operationId("get-my-resource")
  get(@path id: Shared.ULID): Shared.GetResponse<MyResource> | Common.NotFound | Common.ErrorResponses;
}

